SELECT COUNT(*)
FROM hm_query.order_details_flat o

    AND o.order_id = #{id}
    AND o.order_number = #{orderNumber}
    AND o.customer_id = #{customerId}
    AND o.customer_email ILIKE CONCAT('%', #{customerEmail}, '%')
    AND o.customer_phone = #{customerPhone}
    AND o.order_status = #{stateId}
    AND o.payment_status = #{paymentStatus}
    AND o.shipping_status = #{shippingStatus}
    AND o.order_date >= CAST(#{startDate} AS TIMESTAMP)
    AND o.order_date <= CAST(#{endDate} AS TIMESTAMP)
    AND (o.order_number ILIKE CONCAT('%', #{q}, '%') OR o.customer_email ILIKE CONCAT('%', #{q}, '%') OR o.customer_first_name ILIKE CONCAT('%', #{q}, '%') OR o.customer_last_name ILIKE CONCAT('%', #{q}, '%'))

SELECT o.order_id as "orderId", o.order_number as "orderNumber", o.order_status as "orderState", o.total_amount as "totalAmount", o.currency as "currency", o.total_items as "itemCount", o.order_date as "createdTime", o.customer_id as "customerId", o.customer_first_name as "customerFirstName", o.customer_last_name as "customerLastName", o.customer_email as "customerEmail", o.customer_phone as "customerPhone", o.payment_status as "paymentStatus", o.payment_method as "paymentMethod", o.total_amount as "paymentAmount", o.shipping_status as "shippingStatus", o.carrier as "carrier", o.tracking_number as "trackingNumber", o.estimated_delivery as "estimatedDeliveryDate" FROM hm_query.order_details_flat o
AND o.order_id = #{id} AND o.order_number = #{orderNumber} AND o.customer_id = #{customerId} AND o.customer_email ILIKE CONCAT('%', #{customerEmail}, '%') AND o.customer_phone = #{customerPhone} AND o.order_status = #{stateId} AND o.payment_status = #{paymentStatus} AND o.shipping_status = #{shippingStatus} AND o.order_date >= CAST(#{startDate} AS TIMESTAMP) AND o.order_date <= CAST(#{endDate} AS TIMESTAMP) AND (o.order_number ILIKE CONCAT('%', #{q}, '%') OR o.customer_email ILIKE CONCAT('%', #{q}, '%') OR o.customer_first_name ILIKE CONCAT('%', #{q}, '%') OR o.customer_last_name ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*)
FROM hm_query.order_items_flat oi

    AND oi.order_id = #{orderId}
    AND oi.supplier_id = #{supplierId}
    AND oi.fulfillment_status = #{fulfillmentStatus}
    AND (oi.product_name ILIKE CONCAT('%', #{q}, '%') OR oi.sku ILIKE CONCAT('%', #{q}, '%') OR oi.brand ILIKE CONCAT('%', #{q}, '%'))

SELECT oi.item_id as "itemId", oi.order_id as "orderId", oi.product_id as "productId", oi.product_name as "productName", oi.variant_id as "variantId", oi.sku as "sku", oi.quantity as "quantity", oi.unit_price as "unitPrice", oi.total_price as "totalPrice", oi.fulfillment_status as "fulfillmentStatus", oi.supplier_id as "supplierId", oi.brand as "brand", oi.product_slug as "productSlug", '' as "productState", oi.category_id as "categoryId", oi.category_name as "categoryName", 0 as "currentStock", oi.supplier_name as "supplierName" FROM hm_query.order_items_flat oi
AND oi.order_id = #{orderId} AND oi.supplier_id = #{supplierId} AND oi.fulfillment_status = #{fulfillmentStatus} AND (oi.product_name ILIKE CONCAT('%', #{q}, '%') OR oi.sku ILIKE CONCAT('%', #{q}, '%') OR oi.brand ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*)
FROM hm_query.return_detail_flat rr

    AND rr.customer_id = #{customerId}
    AND rr.order_id = #{orderId}
    AND rr.return_status = #{stateId}
    AND rr.return_type = #{returnType}
    AND rr.created_time >= CAST(#{startDate} AS TIMESTAMP)
    AND rr.created_time <= CAST(#{endDate} AS TIMESTAMP)
    AND (rr.reason ILIKE CONCAT('%', #{q}, '%') OR rr.product_name ILIKE CONCAT('%', #{q}, '%') OR rr.sku ILIKE CONCAT('%', #{q}, '%'))

SELECT rr.return_id as "returnId", rr.order_id as "orderId", rr.customer_id as "customerId", rr.reason as "returnReason", rr.return_type as "returnType", rr.refund_amount as "refundAmount", rr.return_status as "returnState", rr.created_time as "returnCreatedTime", o.order_number as "orderNumber", o.total_amount as "orderAmount", o.currency as "orderCurrency", o.order_status as "orderState", o.order_date as "orderCreatedTime", o.customer_first_name as "customerFirstName", o.customer_last_name as "customerLastName", o.customer_email as "customerEmail", o.customer_phone as "customerPhone", o.payment_status as "paymentStatus", o.payment_method as "paymentMethod" FROM hm_query.return_detail_flat rr LEFT JOIN hm_query.order_details_flat o ON rr.order_id = o.order_id
AND rr.customer_id = #{customerId} AND rr.order_id = #{orderId} AND rr.return_status = #{stateId} AND rr.return_type = #{returnType} AND rr.created_time >= CAST(#{startDate} AS TIMESTAMP) AND rr.created_time <= CAST(#{endDate} AS TIMESTAMP) AND (rr.reason ILIKE CONCAT('%', #{q}, '%') OR rr.product_name ILIKE CONCAT('%', #{q}, '%') OR rr.sku ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*)
FROM hm_query.support_ticket_flat t

    AND t.customer_id = #{customerId}
    AND t.order_id = #{orderId}
    AND t.ticket_status = #{stateId}
    AND t.priority = #{priority}
    AND t.assigned_agent_id = #{assignedAgentId}
    AND t.category = #{category}
    AND (t.subject ILIKE CONCAT('%', #{q}, '%') OR t.ticket_id ILIKE CONCAT('%', #{q}, '%'))

SELECT t.ticket_id as "ticketId", t.subject as "subject", t.ticket_status as "ticketState", t.priority as "priority", t.category as "category", t.assigned_agent_id as "assignedAgentId", t.created_time as "ticketCreatedTime", t.customer_id as "customerId", o.customer_first_name as "customerFirstName", o.customer_last_name as "customerLastName", o.customer_email as "customerEmail", t.order_id as "orderId", o.order_number as "orderNumber", o.order_status as "orderState", o.total_amount as "orderAmount", o.currency as "orderCurrency", o.payment_status as "paymentStatus", o.shipping_status as "shippingStatus", o.tracking_number as "trackingNumber" FROM hm_query.support_ticket_flat t LEFT JOIN hm_query.order_details_flat o ON t.order_id = o.order_id
AND t.customer_id = #{customerId} AND t.order_id = #{orderId} AND t.ticket_status = #{stateId} AND t.priority = #{priority} AND t.assigned_agent_id = #{assignedAgentId} AND t.category = #{category} AND (t.subject ILIKE CONCAT('%', #{q}, '%') OR t.ticket_id ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*)
FROM hm_query.settlement_flat st

    AND st.order_id = #{orderId}
    AND st.supplier_id = #{supplierId}
    AND st.settlement_status = #{stateId}
    AND st.period_start >= CAST(#{startDate} AS TIMESTAMP)
    AND st.period_end <= CAST(#{endDate} AS TIMESTAMP)
    AND (st.supplier_name ILIKE CONCAT('%', #{q}, '%') OR st.order_id ILIKE CONCAT('%', #{q}, '%') OR st.settlement_id ILIKE CONCAT('%', #{q}, '%'))

SELECT st.settlement_id as "settlementId", st.order_id as "orderId", st.supplier_id as "supplierId", st.settlement_status as "settlementState", st.order_amount as "orderAmount", st.commission_amount as "commissionAmount", st.commission_rate as "commissionRate", st.platform_fee as "platformFee", st.tds_amount as "tdsAmount", st.gst_on_commission as "gstOnCommission", st.net_payout as "netAmount", st.currency as "currency", st.period_start as "periodStart", st.period_end as "periodEnd", st.created_time as "settlementCreatedTime", o.order_number as "orderNumber", o.order_status as "orderState", o.total_amount as "orderTotal", o.order_date as "orderCreatedTime", st.supplier_name as "supplierName", o.payment_status as "paymentStatus", o.payment_method as "paymentMethod", o.total_amount as "paymentAmount" FROM hm_query.settlement_flat st LEFT JOIN hm_query.order_details_flat o ON st.order_id = o.order_id
AND st.order_id = #{orderId} AND st.supplier_id = #{supplierId} AND st.settlement_status = #{stateId} AND st.period_start >= CAST(#{startDate} AS TIMESTAMP) AND st.period_end <= CAST(#{endDate} AS TIMESTAMP) AND (st.supplier_name ILIKE CONCAT('%', #{q}, '%') OR st.order_id ILIKE CONCAT('%', #{q}, '%') OR st.settlement_id ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*)
FROM hm_query.fulfillment_flat ff

    AND ff.order_id = #{orderId}
    AND ff.fulfillment_status = #{stateId}
    AND ff.warehouse_id = #{warehouseId}
    AND (ff.warehouse_name ILIKE CONCAT('%', #{q}, '%') OR ff.tracking_number ILIKE CONCAT('%', #{q}, '%') OR ff.fulfillment_id ILIKE CONCAT('%', #{q}, '%'))

SELECT ff.fulfillment_id as "fulfillmentId", ff.order_id as "orderId", ff.fulfillment_status as "fulfillmentState", ff.priority as "priority", ff.fulfillment_type as "fulfillmentType", ff.total_items as "totalItems", ff.assigned_picker_id as "assignedPicker", ff.assigned_packer_id as "assignedPacker", ff.pick_started_at as "pickStartedAt", ff.pick_completed_at as "pickCompletedAt", ff.pack_started_at as "packStartedAt", ff.pack_completed_at as "packCompletedAt", ff.shipped_at as "shippedAt", ff.carrier as "carrier", ff.tracking_number as "trackingNumber", ff.estimated_ship_date as "estimatedShipDate", ff.estimated_delivery_date as "estimatedDeliveryDate", ff.created_time as "fulfillmentCreatedTime", ff.warehouse_id as "warehouseId", ff.warehouse_name as "warehouseName", ff.warehouse_code as "warehouseCode", ff.warehouse_city as "warehouseCity", o.order_number as "orderNumber", o.order_status as "orderState", o.total_amount as "orderAmount", o.customer_id as "customerId" FROM hm_query.fulfillment_flat ff LEFT JOIN hm_query.order_details_flat o ON ff.order_id = o.order_id
AND ff.order_id = #{orderId} AND ff.fulfillment_status = #{stateId} AND ff.warehouse_id = #{warehouseId} AND (ff.warehouse_name ILIKE CONCAT('%', #{q}, '%') OR ff.tracking_number ILIKE CONCAT('%', #{q}, '%') OR ff.fulfillment_id ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}
